def load_originals() -> dict[str, str]:
    rows = {}
    with (WORK / "manuscript_paragraphs.csv").open(encoding="utf-8-sig", newline="") as f:
        for row in csv.DictReader(f):
            rows[row["id"]] = row["text"]
    return rows


def replace_para_text(paragraph, text: str) -> None:
    if paragraph.runs:
        paragraph.runs[0].text = text
        for run in paragraph.runs[1:]:
            run.text = ""
    else:
        paragraph.add_run(text)


def md_escape(text: str) -> str:
    return text.replace("|", "\\|").replace("\n", "<br>")


def reason_for(pid: str) -> str:
    return SPECIAL_REASONS.get(pid, "提升学术正式性，压缩冗余表达，并加强句间因果或证据等级衔接。")


def write_report(originals: dict[str, str], applied: list[str]) -> None:
    ref_ids = [pid for pid in applied if int(pid[1:]) >= 169]
    body_ids = [pid for pid in applied if int(pid[1:]) < 169]
    with REPORT.open("w", encoding="utf-8") as f:
        f.write("# 小论文-14 段落润色、逻辑连贯性与引用核查说明\n\n")
        f.write("## 段落级修改表\n\n")
        f.write("| 段落ID | 原段落/句子 | 修改后段落 | 修改原因与逻辑建议 |\n")
        f.write("|---|---|---|---|\n")
        for pid in body_ids:
            f.write(
                f"| {pid} | {md_escape(originals.get(pid, ''))} | "
                f"{md_escape(EDITS[pid])} | {md_escape(reason_for(pid))} |\n"
            )
        f.write("\n## 参考文献格式与准确性修订\n\n")
        f.write("| 段落ID | 原条目 | 修订后条目 | 修订原因 |\n")
        f.write("|---|---|---|---|\n")
        for pid in ref_ids:
            f.write(
                f"| {pid} | {md_escape(originals.get(pid, ''))} | "
                f"{md_escape(EDITS[pid])} | 根据 DOI/Crossref、出版方页面或 arXiv/会议记录补全 DOI、卷页、会议卷或资源类型。 |\n"
            )
        f.write("\n## 数据与引用核查摘要\n\n")
        f.write("- 关键结果数值与本地 source data / SCI1 补强证据文件进行交叉核对；保留 K=32 vs K=4 遗憾变化、多视图兑现收益和跨端点风险三组摘要核心结果。\n")
        f.write("- 修正讨论中有效候选数表述：由约 1.11 改为约 1.01，与 `sci1_reliability_boundary_scorecard.csv` 和正文方法段一致。\n")
        f.write("- DOI/Crossref 审计结果保存于 `output/paper14_work/reference_audit.csv`；补充或规范了 RDKit、ECFP、Random Forest、XGBoost、QSAR、time-split CV、ICML/NeurIPS/arXiv 条目的引用格式。\n")
        f.write("- 未将 TabPFN、九终点全量深度模型面板、时间外前瞻验证或第三方冷启动复跑写成已完成结果。\n")


def validate_docx(path: Path) -> dict:
    with zipfile.ZipFile(path) as z:
        bad = z.testzip()
        doc = ET.fromstring(z.read("word/document.xml"))
        blips = doc.findall(".//{http://schemas.openxmlformats.org/drawingml/2006/main}blip")
        tables = doc.findall(".//{http://schemas.openxmlformats.org/wordprocessingml/2006/main}tbl")
    return {"zip_test": bad or "ok", "figures": len(blips), "tables": len(tables)}


def main() -> None:
    originals = load_originals()
    doc = Document(DOCX_IN)
    doc.core_properties.title = TITLE

    non_empty_index = 0
    applied = []
    missing_ids = set(EDITS)
    for p in doc.paragraphs:
        if not p.text.strip():
            continue
        non_empty_index += 1
        pid = f"P{non_empty_index:03d}"
        if pid in EDITS:
            replace_para_text(p, EDITS[pid])
            applied.append(pid)
            missing_ids.remove(pid)

    if missing_ids:
        raise RuntimeError(f"Paragraph IDs not found: {sorted(missing_ids)}")

    doc.save(DOCX_OUT)
    write_report(originals, applied)
    validation = validate_docx(DOCX_OUT)
    print(
        json.dumps(
            {
                "output": str(DOCX_OUT),
                "report": str(REPORT),
                "applied_edits": len(applied),
                "validation": validation,
            },
            ensure_ascii=False,
            indent=2,
        )
    )


if __name__ == "__main__":
    main()
